import{_ as l,c as a,o as e,ag as i}from"./chunks/framework.9_5zbkGM.js";const _=JSON.parse('{"title":"成为 Tokens 赞助者","description":"","frontmatter":{},"headers":[],"relativePath":"others/sponsor.md","filePath":"others/sponsor.md","lastUpdated":1779596837000}'),o={name:"others/sponsor.md"};function r(d,t,s,n,h,u){return e(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="成为-tokens-赞助者" tabindex="-1">成为 Tokens 赞助者 <a class="header-anchor" href="#成为-tokens-赞助者" aria-label="Permalink to &quot;成为 Tokens 赞助者&quot;">​</a></h1><p>本页说明 Tokens 文档站的赞助位和广告位规则，以及如何成为赞助商。</p><h3 id="位点与定价" tabindex="-1">位点与定价 <a class="header-anchor" href="#位点与定价" aria-label="Permalink to &quot;位点与定价&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>展示方式</th><th>数量限制</th><th>定价</th></tr></thead><tbody><tr><td>赞助位</td><td>【文档右侧边栏/Github Readme】固定展示你的名称 / Logo，常驻曝光</td><td>最多 2 个</td><td>1500 元 / 月</td></tr><tr><td>广告位</td><td>【文档右侧边栏/程序左侧边栏】广告卡片，页面每次加载随机展示其中一条</td><td>多个轮播</td><td>1500 元 / 月</td></tr></tbody></table><h3 id="赞助位规则" tabindex="-1">赞助位规则 <a class="header-anchor" href="#赞助位规则" aria-label="Permalink to &quot;赞助位规则&quot;">​</a></h3><ul><li>当前只开放两个赞助位，先到先得。</li><li>每个赞助位会在右侧边栏「赞助位」区域常驻显示： <ul><li>优先显示你的 Logo（如配置），否则显示你的名称；</li><li>点击卡片会跳转到你配置的网站链接。</li></ul></li></ul><h3 id="广告位规则" tabindex="-1">广告位规则 <a class="header-anchor" href="#广告位规则" aria-label="Permalink to &quot;广告位规则&quot;">​</a></h3><ul><li>支持配置多条广告，每条包含图片（可选）、标题、描述、跳转链接。</li><li>用户每次打开页面时，会从所有广告中随机选一条展示，你的广告将获得对应的曝光机会。</li><li>点击整块广告卡片会跳转到你配置的网站链接。</li></ul><h3 id="如何成为赞助商" tabindex="-1">如何成为赞助商 <a class="header-anchor" href="#如何成为赞助商" aria-label="Permalink to &quot;如何成为赞助商&quot;">​</a></h3><ol><li>准备好以下信息： <ul><li>赞助类型：选择赞助位或广告位（也可以同时选择）。</li><li>展示名称：你的品牌 / 产品名。</li><li>Logo 图片地址（可选，建议使用透明 PNG 或 SVG）。</li><li>跳转链接：点击后希望打开的网站地址。</li></ul></li><li>通过文档中的「联系作者」页面与作者取得联系： <ul><li>说明「申请 Tokens 文档赞助」，并附上上述信息；</li><li>商议投放时长（按月计费）和起始时间；</li><li>完成支付后，我们会在约定时间内完成配置与上线。</li></ul></li></ol><p>配置完成后：</p><ul><li>你的信息会出现在对应的赞助位或广告位上；</li><li>若在赞助期内需要更新 Logo / 链接 / 文案，可随时联系作者进行调整。</li></ul>',12)])])}const p=l(o,[["render",r]]);export{_ as __pageData,p as default};
